/**
 * @summary Department-wise analytics
 */
export const getGetDepartmentAnalyticsUrl = (
  departmentId: number,
  params?: GetDepartmentAnalyticsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/analytics/department/${departmentId}?${stringifiedParams}`
    : `/api/analytics/department/${departmentId}`;
};

